const SENSITIVE_PATTERNS = [
  // API keys (common formats)
  /(['"`]?)(api[_-]?key|apikey|token|secret|password|pass)['"`]?\s*[:=]\s*['"`]?([a-zA-Z0-9_-]{20,})['"`]?/gi,
